INSERT INTO `servicios` VALUES (1,'Turista','Asientos amplios en coches cÃ³modos con calefacciÃ³n, baÃ±os y dispenser de agua.'),(2,'Turista Comedor','Asientos amplios en coches cÃ³modos con calefacciÃ³n, baÃ±os y dispenser de agua. Adicionalmente se brinda acceso al coche comedor con comida incluida.'),(3,'Pullman','Asientos mÃ¡s anchos y reclinables, distribuidos de a pares, ideales para viajes largos. Cuenta con acceso a personas con movilidad reducida.'),(4,'Pullman Comedor','Asientos mÃ¡s anchos y reclinables, distribuidos de a pares, ideales para viajes largos. Adicionalmente se brinda acceso al coche comedor con comida incluida.'),(5,'Camarote','Compartimento para dos personas con camas marineras, mesita, control de temperatura y privacidad. Incluye sÃ¡banas, mantas y almohadas. Todos incluyen acceso al coche comedor.');
